const body = $input.first().json.body ?? $input.first().json;
const from    = String(body.from ?? '').replace(/^\+/, '');
const message = String(body.message ?? '').trim();
const orgId   = String(body.org_id ?? '');
if (!from || !message || !orgId) throw new Error('Missing fields: ' + JSON.stringify({ from, message, orgId }));
return [{ json: { from, message, org_id: orgId } }];

const userId = $('Build Context').item.json.user_id;
const orgId = $('Build Context').item.json.org_id;
const result = await helpers.httpRequest({
  method: 'GET',
  url: $env.SUPABASE_URL + '/rest/v1/tasks?assignee_id=eq.' + userId + '&status=not.in.(done,cancelled)&deleted_at=is.null&organization_id=eq.' + orgId + '&select=id,title,deadline,priority,status,assignee:users!tasks_assignee_id_fkey(full_name)&order=deadline.asc.nullslast&limit=20',
  headers: { apikey: $env.SUPABASE_SERVICE_ROLE, Authorization: 'Bearer ' + $env.SUPABASE_SERVICE_ROLE }
});
return JSON.stringify(result);

const userId = $('Build Context').item.json.user_id;
const orgId = $('Build Context').item.json.org_id;
const result = await helpers.httpRequest({
  method: 'POST',
  url: $env.SUPABASE_URL + '/rest/v1/rpc/attendance_check_in',
  headers: { apikey: $env.SUPABASE_SERVICE_ROLE, Authorization: 'Bearer ' + $env.SUPABASE_SERVICE_ROLE, 'Content-Type': 'application/json' },
  body: JSON.stringify({ p_user_id: userId, p_org_id: orgId })
});
return JSON.stringify(result);

