const userId = $('Build Context').item.json.user_id;
const orgId = $('Build Context').item.json.org_id;
const now = new Date();
const monthStart = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
const result = await helpers.httpRequest({
  method: 'GET',
  url: $env.SUPABASE_URL + '/rest/v1/attendance?user_id=eq.' + userId + '&organization_id=eq.' + orgId + '&date=gte.' + monthStart + '&select=date,check_in_time,check_out_time,status&order=date.desc&limit=31',
  headers: { apikey: $env.SUPABASE_SERVICE_ROLE, Authorization: 'Bearer ' + $env.SUPABASE_SERVICE_ROLE }
});
return JSON.stringify(result);

const orgId = $('Build Context').item.json.org_id;
const today = new Date().toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });
const result = await helpers.httpRequest({
  method: 'GET',
  url: $env.SUPABASE_URL + '/rest/v1/attendance?organization_id=eq.' + orgId + '&date=eq.' + today + '&select=status,user:users(full_name,role)',
  headers: { apikey: $env.SUPABASE_SERVICE_ROLE, Authorization: 'Bearer ' + $env.SUPABASE_SERVICE_ROLE }
});
return JSON.stringify(result);

const isGreeting = $('Build Context').item.json.is_greeting;
const aiOutput = $('AI Agent').item.json.output;

if (!isGreeting) {
  return [{ json: { output: aiOutput } }];
}

// Extract the pre-written greeting from the system prompt
const sp = $('Build Context').item.json.system_prompt;
const marker = 'Do NOT call any tools. Do NOT add anything:\n\n';
const idx = sp.indexOf(marker);
const greetText = idx >= 0
  ? sp.substring(idx + marker.length)
  : `Hello ${$('Build Context').item.json.user_name}! I am *HRBot*, your AI HR assistant.

*Here is what I can help you with:*
- *Tasks* - list, create, or update tasks
- *Attendance* - check in/out, view history
- *Leaves* - check balance, apply for leave
- *Daily briefing* - today's summary
- *Team attendance* - admin only

What would you like to do?`;

return [{ json: { output: greetText } }];

